    end
  end

  describe "options_newline_spaces" do
    test "options_newline_spaces" do
      options = %HtmlToMarkdown.ConversionOptions{newline_style: "Spaces"}
      {:ok, result} = HtmlToMarkdown.convert("<p>First<br>Second</p>", options)
      assert String.contains?(to_string(result.content), "First")
      assert String.contains?(to_string(result.content), "Second")
    end
  end

  describe "options_output_format_djot" do
    test "options_output_format_djot" do
      options = %HtmlToMarkdown.ConversionOptions{output_format: "Djot"}
      {:ok, result} = HtmlToMarkdown.convert("<p>Simple paragraph.</p>", options)
      assert result.content != ""
      assert String.contains?(to_string(result.content), "Simple paragraph.")
    end
  end

  describe "options_output_format_markdown" do
    test "options_output_format_markdown" do
      options = %HtmlToMarkdown.ConversionOptions{heading_style: "Atx", output_format: "Markdown"}
      {:ok, result} = HtmlToMarkdown.convert("<h1>Title</h1><p>Some text.</p>", options)
      assert String.contains?(to_string(result.content), "\# Title")
      assert String.contains?(to_string(result.content), "Some text.")
    end
  end

  describe "options_output_format_plain" do
    test "options_output_format_plain" do
      options = %HtmlToMarkdown.ConversionOptions{output_format: "Plain"}
      {:ok, result} = HtmlToMarkdown.convert("<h1>Title</h1><p>Some <strong>bold</strong> text.</p>", options)
      assert String.contains?(to_string(result.content), "Title")
      assert String.contains?(to_string(result.content), "bold")
      assert String.contains?(to_string(result.content), "text.")
    end
  end

  describe "options_preprocessing_aggressive" do
    test "options_preprocessing_aggressive" do
      options = %HtmlToMarkdown.ConversionOptions{preprocessing: %{"preset" => "Aggressive"}}
      {:ok, result} = HtmlToMarkdown.convert("<nav>Menu</nav><article><h1>Title</h1><p>Content</p></article><aside>Sidebar</aside><footer>Footer</footer>", options)
      assert String.contains?(to_string(result.content), "Title")
      assert String.contains?(to_string(result.content), "Content")
      refute String.contains?(to_string(result.content), "Menu")
    end
  end

  describe "options_preprocessing_enabled_false_skips_cleanup" do
    test "options_preprocessing_enabled_false_skips_cleanup" do
      options = %HtmlToMarkdown.ConversionOptions{preprocessing: %{"enabled" => false}}
      {:ok, result} = HtmlToMarkdown.convert("<nav>NavSection</nav><p>Paragraph</p>", options)
      assert String.contains?(to_string(result.content), "NavSection")
      assert String.contains?(to_string(result.content), "Paragraph")
    end
  end

  describe "options_preprocessing_minimal" do
    test "options_preprocessing_minimal" do
      options = %HtmlToMarkdown.ConversionOptions{preprocessing: %{"preset" => "Minimal"}}
      {:ok, result} = HtmlToMarkdown.convert("<nav>Navigation</nav><p>Content</p><footer>Footer</footer>", options)
      assert String.contains?(to_string(result.content), "Navigation")
      assert String.contains?(to_string(result.content), "Content")
      assert String.contains?(to_string(result.content), "Footer")
    end
  end

  describe "options_preprocessing_remove_forms" do
    test "options_preprocessing_remove_forms" do
      options = %HtmlToMarkdown.ConversionOptions{preprocessing: %{"remove_forms" => true}}
      {:ok, result} = HtmlToMarkdown.convert("<p>Before</p><form><input type='text'/><button>Submit</button></form><p>After</p>", options)
      assert String.contains?(to_string(result.content), "Before")
      assert String.contains?(to_string(result.content), "After")
      refute String.contains?(to_string(result.content), "Submit")
    end
  end

  describe "options_preprocessing_remove_navigation_false_keeps_nav" do
    test "options_preprocessing_remove_navigation_false_keeps_nav" do
      options = %HtmlToMarkdown.ConversionOptions{preprocessing: %{"remove_navigation" => false}}
      {:ok, result} = HtmlToMarkdown.convert("<nav>SiteMenu</nav><main><p>MainContent</p></main><aside>SidebarText</aside>", options)
      assert String.contains?(to_string(result.content), "SiteMenu")
      assert String.contains?(to_string(result.content), "MainContent")
      assert String.contains?(to_string(result.content), "SidebarText")
    end
  end

  describe "options_preserve_tags_iframe" do
    test "options_preserve_tags_iframe" do
      options = %HtmlToMarkdown.ConversionOptions{preserve_tags: ["iframe"]}
      {:ok, result} = HtmlToMarkdown.convert("<p>Before</p><iframe src='video.html' width='560'></iframe><p>After</p>", options)
      assert String.contains?(to_string(result.content), "Before")
      assert String.contains?(to_string(result.content), "After")
      assert String.contains?(to_string(result.content), "<iframe")
    end
  end

  describe "options_skip_images_true" do
    test "options_skip_images_true" do
      options = %HtmlToMarkdown.ConversionOptions{skip_images: true}
      {:ok, result} = HtmlToMarkdown.convert("<p>Before <img src='test.jpg' alt='photo'> After</p>", options)
      assert String.contains?(to_string(result.content), "Before")
      assert String.contains?(to_string(result.content), "After")
      refute String.contains?(to_string(result.content), "photo")
    end
  end

  describe "options_strip_newlines" do
    test "options_strip_newlines" do
      options = %HtmlToMarkdown.ConversionOptions{strip_newlines: true}
      {:ok, result} = HtmlToMarkdown.convert("<p>First paragraph.</p><p>Second paragraph.</p>", options)
      assert String.contains?(to_string(result.content), "First paragraph.")
      assert String.contains?(to_string(result.content), "Second paragraph.")
    end
  end

  describe "options_strip_tags_div_span" do
    test "options_strip_tags_div_span" do
      options = %HtmlToMarkdown.ConversionOptions{strip_tags: ["div", "span"]}
      {:ok, result} = HtmlToMarkdown.convert("<div class='wrapper'><p>Inside div</p></div><p>Outside <span class='hl'>span text</span></p>", options)
      assert String.contains?(to_string(result.content), "Inside div")
      assert String.contains?(to_string(result.content), "span text")
    end
  end

  describe "options_strong_em_underscore" do
    test "options_strong_em_underscore" do
      options = %HtmlToMarkdown.ConversionOptions{strong_em_symbol: "_"}
      {:ok, result} = HtmlToMarkdown.convert("<p><strong>bold</strong> and <em>italic</em></p>", options)
      assert String.contains?(to_string(result.content), "__bold__")
      assert String.contains?(to_string(result.content), "_italic_")
    end
  end

  describe "options_sub_symbol_tilde" do
    test "options_sub_symbol_tilde" do
      options = %HtmlToMarkdown.ConversionOptions{sub_symbol: "~"}
      {:ok, result} = HtmlToMarkdown.convert("<p>H<sub>2</sub>O</p>", options)
      assert String.contains?(to_string(result.content), "~2~")
    end
  end

  describe "options_sup_symbol_caret" do
    test "options_sup_symbol_caret" do
      options = %HtmlToMarkdown.ConversionOptions{sup_symbol: "^"}
      {:ok, result} = HtmlToMarkdown.convert("<p>x<sup>2</sup></p>", options)
      assert String.contains?(to_string(result.content), "^2^")
    end
  end

  describe "options_url_escape_style_angle_default" do
    test "options_url_escape_style_angle_default" do
      options = %HtmlToMarkdown.ConversionOptions{url_escape_style: "angle"}
      {:ok, result} = HtmlToMarkdown.convert("<a href=\"/file (1).pdf\">file</a>", options)
      assert String.contains?(to_string(result.content), "</file (1).pdf>")
    end
  end

  describe "options_url_escape_style_percent_angle_brackets_in_url" do
    test "options_url_escape_style_percent_angle_brackets_in_url" do
      options = %HtmlToMarkdown.ConversionOptions{url_escape_style: "percent"}
      {:ok, result} = HtmlToMarkdown.convert("<a href=\"/file (1) <draft>.pdf\">file</a>", options)
      assert String.contains?(to_string(result.content), "/file%20%281%29%20%3Cdraft%3E.pdf")
    end
  end

  describe "options_url_escape_style_percent_image" do
    test "options_url_escape_style_percent_image" do
      options = %HtmlToMarkdown.ConversionOptions{url_escape_style: "percent"}
      {:ok, result} = HtmlToMarkdown.convert("<img src=\"/img (1) <draft>.png\" alt=\"alt\">", options)
      assert String.contains?(to_string(result.content), "/img%20%281%29%20%3Cdraft%3E.png")
    end
  end

  describe "options_url_escape_style_percent_link" do
    test "options_url_escape_style_percent_link" do
      options = %HtmlToMarkdown.ConversionOptions{url_escape_style: "percent"}
      {:ok, result} = HtmlToMarkdown.convert("<a href=\"/file (1).pdf\">file</a>", options)
      assert String.contains?(to_string(result.content), "/file%20%281%29.pdf")
      refute String.contains?(to_string(result.content), "</")
    end
  end

  describe "options_whitespace_normalized" do
    test "options_whitespace_normalized" do
      options = %HtmlToMarkdown.ConversionOptions{whitespace_mode: "Normalized"}
      {:ok, result} = HtmlToMarkdown.convert("<p>Text   with    extra   spaces.</p>", options)
      assert result.content != ""
      assert String.contains?(to_string(result.content), "Text")
      assert String.contains?(to_string(result.content), "with")
      assert String.contains?(to_string(result.content), "extra")
      assert String.contains?(to_string(result.content), "spaces.")
    end
  end

  describe "options_whitespace_strict" do
    test "options_whitespace_strict" do
      options = %HtmlToMarkdown.ConversionOptions{whitespace_mode: "Strict"}
      {:ok, result} = HtmlToMarkdown.convert("<p>Preserved   spacing.</p>", options)
      assert result.content != ""
      assert String.contains?(to_string(result.content), "Preserved")
      assert String.contains?(to_string(result.content), "spacing.")
    end
  end

  describe "options_wrap_disabled" do
    test "options_wrap_disabled" do
      options = %HtmlToMarkdown.ConversionOptions{wrap: false}
      {:ok, result} = HtmlToMarkdown.convert("<p>This is a long paragraph that should not be wrapped at all because wrapping is disabled.</p>", options)
      assert String.contains?(to_string(result.content), "This is a long paragraph that should not be wrapped at all because wrapping is disabled.")
    end
  end

  describe "options_wrap_enabled" do
    test "options_wrap_enabled" do
      options = %HtmlToMarkdown.ConversionOptions{wrap: true, wrap_width: 40}
      {:ok, result} = HtmlToMarkdown.convert("<p>This is a long paragraph that should be wrapped at the specified column width when the wrap option is enabled.</p>", options)
      assert result.content != ""
      assert String.contains?(to_string(result.content), "This is a long paragraph")
    end
  end
end
